import 'package:flutter/material.dart';
import 'package:go_router/go_router.dart';
import '../../../../../generated/catalog.dart';
import '../../../../../shared/layout/responsive_scaffold.dart';
class ModulesPage extends StatelessWidget { const ModulesPage({super.key}); @override Widget build(BuildContext context) => ResponsiveScaffold(title: 'Módulos e requisitos', child: ListView(padding: const EdgeInsets.all(24), children: [Text('Cobertura funcional completa', style: Theme.of(context).textTheme.headlineSmall), const SizedBox(height: 8), const Text('20 módulos e 134 requisitos mapeados com CRUD multi-tenant e workflows no backend.'), const SizedBox(height: 24), LayoutBuilder(builder: (context, c) { final cols = c.maxWidth >= 1100 ? 3 : c.maxWidth >= 720 ? 2 : 1; return GridView.builder(shrinkWrap: true, physics: const NeverScrollableScrollPhysics(), itemCount: moduleCatalog.length, gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(crossAxisCount: cols, mainAxisSpacing: 16, crossAxisSpacing: 16, childAspectRatio: 1.65), itemBuilder: (context, i) { final m = moduleCatalog[i]; return Card(child: InkWell(onTap: () => context.go('/modulos/${Uri.encodeComponent(m['name'].toString())}'), child: Padding(padding: const EdgeInsets.all(20), child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [Text(m['name'].toString(), style: Theme.of(context).textTheme.titleMedium, maxLines: 2, overflow: TextOverflow.ellipsis), const Spacer(), Wrap(spacing: 8, children: [Chip(label: Text('${m['requirements']} RFs')), Chip(label: Text('${m['must']} Must')), Chip(label: Text('${m['entities']} entidades'))])])))); }); })])); }
class ModuleDetailPage extends StatelessWidget { const ModuleDetailPage({required this.moduleName, super.key}); final String moduleName; @override Widget build(BuildContext context) { final reqs = requirementCatalog.where((i) => i['module'] == moduleName).toList(); final ents = entityCatalog.where((i) => i['module'] == moduleName).toList(); return ResponsiveScaffold(title: moduleName, child: ListView(padding: const EdgeInsets.all(24), children: [Text('Requisitos funcionais', style: Theme.of(context).textTheme.titleLarge), const SizedBox(height: 12), for (final r in reqs) Card(child: ListTile(leading: CircleAvatar(child: Text(r['id'].toString().replaceAll('RF-', ''))), title: Text(r['title'].toString()), subtitle: Text('Prioridade: ${r['priority']}'))), const SizedBox(height: 24), Text('Entidades do módulo', style: Theme.of(context).textTheme.titleLarge), const SizedBox(height: 12), for (final e in ents) Card(child: ListTile(title: Text(e['name'].toString()), subtitle: Text(e['description'].toString()), trailing: const Icon(Icons.chevron_right), onTap: () => context.go('/entidades/${e['table']}')))])); } }
